static void
ui_print_m17_data_type(int dt) {
    switch (dt) {
        case 0: printw("Reserved"); break;
        case 1: printw("Data "); break;
        case 2: printw("Voice (3200) "); break;
        case 3: printw("Voice (1600) + Data"); break;
        default: break;
    }
}

static void
ui_print_m17_encryption_details(dsd_state* state) {
    //fill in any extra info, like Meta (IV, etc)
    if (state->m17_enc == 1) {
        printw(" Scrambler - Type: %d", state->m17_enc_st);
    }

    if (state->m17_enc == 2) {
        attron(COLOR_PAIR(1));
        printw("AES-CTR - IV: ");
        //display packed meta as IV
        for (int i = 0; i < 16; i++) {
            printw("%02X", state->m17_meta[i]);
        }
    }

    if (state->m17_enc == 3) {
        printw(" Reserved Enc - Type: %d", state->m17_enc_st);
    }
}

static void
ui_render_call_info_m17(dsd_state* state) {
    //M17
    if (lls == DSD_SYNC_M17_STR_POS || lls == DSD_SYNC_M17_STR_NEG || lls == DSD_SYNC_M17_LSF_POS
        || lls == DSD_SYNC_M17_LSF_NEG) {

        printw("| ");
        printw("M17: ");

        //insert data type and frame information
        ui_print_m17_data_type(state->m17_str_dt);

        printw("\n");
        printw("| ");

        printw("DST: ");
        const uint8_t dst_kind = m17_address_classify(state->m17_dst);
        if (dst_kind == M17_ADDRESS_BROADCAST_KIND) {
            printw("BROADCAST ");
        } else if (dst_kind == M17_ADDRESS_EXTENDED) {
            printw("EXTENDED (%012llx) ", state->m17_dst);
        } else if (dst_kind == M17_ADDRESS_RESERVED) {
            printw("RESERVED (%012llx) ", state->m17_dst);
        } else {
            printw("%s", state->m17_dst_str);
        }

        printw("\n");
        printw("| ");

        printw("SRC: ");
        const uint8_t src_kind = m17_address_classify(state->m17_src);
        if (src_kind == M17_ADDRESS_BROADCAST_KIND) {
            printw("UNKNOWN FFFFFFFFFFFF");
        } else if (src_kind == M17_ADDRESS_EXTENDED) {
            printw("EXTENDED (%012llx)", state->m17_src);
        } else if (src_kind == M17_ADDRESS_RESERVED) {
            printw("RESERVED (%012llx)", state->m17_src);
        } else {
            printw("%s", state->m17_src_str);
        }

        printw("\n");
        printw("| ");

        printw("CAN: %02d ", state->m17_can);

        printw("\n");
        printw("| ");

        ui_print_m17_encryption_details(state);

        printw("\n");
    }
}

